from ariadne import gql, make_executable_schema
from ariadne.constants import PLAYGROUND_HTML
from flask import Flask, request, jsonify, g
from functools import wraps
import jwt
import os

# Mock database
users_db = {
    1: {
        "id": 1,
        "username": "john_doe",
        "bio": "Software developer",
        "email": "john@example.com",
        "phone": "+1234567890",
        "address": "123 Main St"
    },
    2: {
        "id": 2,
        "username": "jane_smith",
        "bio": "Product manager",
        "email": "jane@example.com",
        "phone": "+0987654321",
        "address": "456 Oak Ave"
    }
}

posts_db = {
    1: {
        "id": 1,
        "title": "First Post",
        "content": "This is the first post",
        "author_id": 1
    }
}

# GraphQL schema
type_defs = gql("""
    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }

    type Query {
        user(id: ID!): User
        users: [User!]!
        me: User
        posts: [Post!]!
        post(id: ID!): Post
    }
""")

# Resolvers
def resolve_user(_, info, id):
    user_data = users_db.get(int(id))
    if not user_data:
        return None
    return user_data

def resolve_users(_, info):
    return list(users_db.values())

def resolve_me(_, info):
    if hasattr(g, 'current_user') and g.current_user:
        return users_db.get(g.current_user['id'])
    return None

def resolve_posts(_, info):
    return list(posts_db.values())

def resolve_post(_, info, id):
    post_data = posts_db.get(int(id))
    if not post_data:
        return None
    # Add author to post data
    author = users_db.get(post_data['author_id'])
    post_data['author'] = author
    return post_data

# Field resolvers for User type
def resolve_user_id(user, info):
    return str(user['id'])

def resolve_user_username(user, info):
    return user['username']

def resolve_user_bio(user, info):
    return user['bio']

def resolve_user_email(user, info):
    if hasattr(g, 'current_user') and g.current_user and g.current_user['id'] == user['id']:
        return user.get('email')
    return None

def resolve_user_phone(user, info):
    if hasattr(g, 'current_user') and g.current_user and g.current_user['id'] == user['id']:
        return user.get('phone')
    return None

def resolve_user_address(user, info):
    if hasattr(g, 'current_user') and g.current_user and g.current_user['id'] == user['id']:
        return user.get('address')
    return None

# Field resolvers for Post type
def resolve_post_id(post, info):
    return str(post['id'])

def resolve_post_title(post, info):
    return post['title']

def resolve_post_content(post, info):
    return post['content']

def resolve_post_author(post, info):
    return post['author']

# Schema configuration
resolvers = {
    "Query": {
        "user": resolve_user,
        "users": resolve_users,
        "me": resolve_me,
        "posts": resolve_posts,
        "post": resolve_post
    },
    "User": {
        "id": resolve_user_id,
        "username": resolve_user_username,
        "bio": resolve_user_bio,
        "email": resolve_user_email,
        "phone": resolve_user_phone,
        "address": resolve_user_address
    },
    "Post": {
        "id": resolve_post_id,
        "title": resolve_post_title,
        "content": resolve_post_content,
        "author": resolve_post_author
    }
}

schema = make_executable_schema(type_defs, resolvers)

# Flask app
app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-here')

# Authentication middleware
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({"error": "Authorization header required"}), 401
        
        token = auth_header.split(' ')[1]
        try:
            payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            g.current_user = payload
        except jwt.ExpiredSignatureError:
            return jsonify({"error": "Token has expired"}), 401
        except jwt.InvalidTokenError:
            return jsonify({"error": "Invalid token"}), 401
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/graphql', methods=['GET', 'POST'])
@require_auth
def graphql_server():
    if request.method == 'GET':
        return PLAYGROUND_HTML, 200
    
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    
    result = schema.execute(data.get('query'), variable_values=data.get('variables'))
    
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)